import React, { useEffect } from 'react';
import { Container, Row, Col } from 'react-bootstrap'; 
// Importaciones críticas desde ../components/
import HeroSection from '../components/HeroSection'; // Ruta corregida
import ProductList from '../components/ProductList'; 
import FilterSidebar from '../components/FilterSidebar'; // Ruta corregida
// Importación del hook (asumimos que existe en la carpeta hooks/)
import useProductFilters from '../hooks/useProductFilters'; // Ruta corregida

// Este componente es la página principal con el diseño Dark Tecnotitlan.
const HomeScreen = () => {
    // Inicializamos la lógica de filtros (simulada o real)
    const {
        products, loading, error, pages, page, setPage,
        categories, selectedCategory, setSelectedCategory, handleClearFilters,
    } = useProductFilters(); 

    // Asegurar que la página siempre se cargue en la parte superior.
    useEffect(() => {
        window.scrollTo(0, 0);
    }, [page]);

    // 1. Estilo para la tarjeta de filtros (Sticky Card)
    const filterPanelStyle = {
        backgroundColor: 'var(--card-bg-color)', // Blanco
        borderRadius: '16px',
        padding: '1.5rem',
        boxShadow: '0 10px 40px rgba(0,0,0,0.1)', // Sombra flotante sutil
        position: 'sticky',
        top: '100px', // Se pega debajo del Header (altura aprox.)
        border: '1px solid #E2E8F0',
        zIndex: 10
    };

    return (
        // El contenido completo de la Home (Dark Tecnotitlan)
        <>
            {/* 1. HERO SECTION: Borde a borde, diseño oscuro */}
            <HeroSection />

            {/* 2. SECCIÓN DE CONTENIDO FLOTANTE: Fondo gris muy claro para contraste */}
            {/* secondary-bg-color es el gris claro que contrasta con el Hero oscuro */}
            <div style={{ backgroundColor: 'var(--secondary-bg-color)', minHeight: '100vh', paddingBottom: '4rem' }}>
                
                {/* Margen negativo CRÍTICO para 'levantar' el contenido sobre el Hero */}
                {/* -mt-16 = margin-top: -4rem. Esto hace que el contenido flote. */}
                <Container className="pt-0 -mt-16 z-20 relative"> 
                    <Row>
                        {/* --- COLUMNA IZQUIERDA: FILTROS (Panel Flotante) --- */}
                        <Col lg={3} className="d-none d-lg-block">
                            <div style={filterPanelStyle}>
                                {/* Título del panel de filtros */}
                                <div className="d-flex align-items-center gap-2 mb-4 pb-3 border-bottom border-gray-200">
                                    <i className="fas fa-sliders-h text-xl" style={{ color: 'var(--cta-color)' }}></i>
                                    <h5 className="mb-0 font-bold text-slate-800" style={{ fontWeight: 700 }}>Filtros</h5>
                                </div>

                                <FilterSidebar
                                    categories={categories}
                                    selectedCategory={selectedCategory}
                                    setSelectedCategory={setSelectedCategory}
                                    handleClearFilters={handleClearFilters}
                                />
                            </div>
                        </Col>

                        {/* --- COLUMNA DERECHA: GRID DE PRODUCTOS --- */}
                        {/* CRÍTICO: Añadimos pl-0 para eliminar el padding izquierdo en pantallas grandes y alinearlo */}
                        <Col lg={9} className="pl-lg-0"> 
                            {/* AJUSTE: Añadimos pt-4 para que el contenido no se pegue al borde superior del div blanco */}
                            <div className="bg-white p-6 rounded-xl shadow-xl min-h-[500px] border border-gray-100 pt-4">
                                
                                <ProductList
                                    products={products}
                                    loading={loading}
                                    error={error}
                                    pages={pages}
                                    page={page}
                                    setPage={setPage}
                                />
                                
                            </div>
                        </Col>
                    </Row>
                </Container>
            </div>
        </>
    );
};

export default HomeScreen;
